import java.io.*;
import java.util.*;
import org.owasp.esapi.ESAPI;

public class XSSFixedCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Sanitize and encode user input to prevent XSS
        String sanitizedInput = ESAPI.encoder().encodeForHTML(userInput);

        // Output the sanitized input
        System.out.println("<h1>Welcome, " + sanitizedInput + "!</h1>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
